var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"안젤라 씨 덕분에 당장 급한 불은 끄긴 했는데…….","JPN":"アンジェラさんのおかげで急場はしのげましたけど……","ENG":"Thanks to Angela, the fire was put out right away.","TWN":"安潔拉小姐，謝謝你的神救援……"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"저거…… 건물이 무너지는 거 맞죠? 반군들이 폭탄이라도 터뜨린 건가?","JPN":"あれ……建物が崩れてるんですよね？　反乱軍が爆弾でも爆発させたのかな？","ENG":"That... That building is collapsing, right? Did the rebels detonate a bomb or something?","TWN":"那是……整棟建築物倒塌？叛軍是有引爆炸彈嗎？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"아니야. 이 느낌은…….","JPN":"違う。この感じは……","ENG":"That’s not it. This feeling...","TWN":"不對，這感覺……"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"잠깐만요. 지금 쓰러진 건물, 우리와 그렇게 멀지 않은 곳인 것 같은데…….","JPN":"ちょっと待ってください。今崩れた建物、私たちの位置とそう遠くない場所のようですけど……","ENG":"Wait a second. That building doesn’t seem all that far from us...","TWN":"等等，那棟倒塌的建築物好像離我們不遠……"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"오늘은 공기가 많이 나쁘네……. 감기 안 걸리게 집으로 가야겠어요.","JPN":"今日は空気が良くないわね……風邪を引かないように家に帰りましょう。","ENG":"The air quality is so bad today... We should go home so we don’t catch a cold.","TWN":"今天的空氣不太好……我們趕快回家才不會感冒。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"어디로 갈지는 모르겠고 일단 피하기나 하죠!","JPN":"どこへ行くかはわかりませんけど、まずは避難しましょう！","ENG":"I don’t where we’re going, but let’s just avoid that area for now!","TWN":"我不知道還能去哪裡，總之先躲好吧！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"커윽……! 으……!","JPN":"くうっ……！　う……！","ENG":"Kagh...! Ugh...!","TWN":"唔……！呃……！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"레아 씨?!","JPN":"レアさん！？","ENG":"Leah?!","TWN":"蕾亞小姐？！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"레아!!","JPN":"レア！！","ENG":"Leah!!","TWN":"蕾亞！！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"세상에……. 온몸이 만신창이야.","JPN":"そんな……全身がボロボロよ。","ENG":"Oh my... Her entire body is in tatters.","TWN":"怎麼會這樣……你傷得好嚴重！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"레아, 눈 좀 떠 봐! 레아!!","JPN":"レア、目を開けて！　レア！！","ENG":"Leah, open your eyes! Leah!!","TWN":"蕾亞，睜開眼睛！蕾亞！！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"안…… 젤라……?","JPN":"アン……ジェラ……？","ENG":"Angela...?","TWN":"安……潔拉……？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"왜 아직도……. 여기 있는 거야? 어서 도망치지 않고……!","JPN":"どうしてまだ……ここにいるの？　早く逃げないと……！","ENG":"Why... Why are you still here? You should run...!","TWN":"你們……怎麼還在這裡？快逃……！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"필사적인 저항이로군.","JPN":"必死な抗いだ。","ENG":"Such desperate resistance.","TWN":"看來你是打算誓死抵抗是嗎？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"허나 안식을 거부하기에는 부질없도다.","JPN":"だが、安息を拒むには儚い限りであるな。","ENG":"However, eternal rest is inevitable.","TWN":"不過也只是浪費力氣。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"뭐, 뭔데 또? 로봇, 아니, 사람인가……?","JPN":"ま、また何？　ロボット、いや、人……？","ENG":"Wha-What is that? A robot, no, a human...?","TWN":"你又是什麼誰？機器人？還是人……？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"아니. 저건 모르스야, 중사님.","JPN":"ううん。あれはモールスよ、軍曹さん。","ENG":"It is Mors, Sergeant.","TWN":"她是莫爾斯，中士。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_SERIOUS"}}}},{"id":"L33_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"모르스……? 반군이 아닌 건가요?","JPN":"モールス……？　反乱軍ではないんですか？","ENG":"Mors...? Not a rebel?","TWN":"莫爾斯……？所以不是叛軍？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_SERIOUS"}}}},{"id":"L34_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"응. 그보다 위험한 존재야.","JPN":"うん。それよりもっと危ない存在なの。","ENG":"Yes. She is something far, far more dangerous.","TWN":"嗯，她比叛軍還危險。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"뒤에 숨어 있어. 언니가 지켜 줄게.","JPN":"後ろに隠れていて。お姉ちゃんが守ってあげる。","ENG":"Get behind me. I will protect you.","TWN":"在後面躲好，姊姊會保護你們！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L37_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"다른 이들을 휘말리게 하지 말라, 여인이여.","JPN":"よその者を巻き込むでない、女よ。","ENG":"Do not involve the others.","TWN":"女人，不要把其他人也拖下水。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"지금 안식으로 인도할 존재는 그대 하나로 충분할지니.","JPN":"ただいま安息へと導くべき存在は貴様一人で十分だ。","ENG":"It is your existence alone that is required.","TWN":"現在需要進入安息的唯有你。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"큭……!","JPN":"くっ……！","ENG":"Khhk...!","TWN":"呃……！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L41_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"레아! 저건 지금 네 힘으로 못 막아! 도망치자, 응?","JPN":"レア！　あれは今のあなたの力では防げないわ！　逃げましょう、ね？","ENG":"Leah! It’s too strong for you! Let’s get out of here, okay?","TWN":"蕾亞！你現在是打不過她的！快逃吧！好不好？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"나도 알아. 무인함에 숨겨 뒀던 폭약을 전부 사용했는데도 흠집 하나 못 냈어.","JPN":"知ってる。無人艦に隠しておいた爆弾を全部使い切ったけど、傷一つなかった。","ENG":"I know. I used all the explosives hidden in the locker but it couldn't make any scratch.","TWN":"我也知道我打不過她，我把藏在無人艦上炸彈全都引爆，也沒能傷她一絲一毫。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"하지만 중사에 너만 있다면 몰라도…….","JPN":"でも軍曹とアンジェラだけならともかく……","ENG":"Still, if it was just you and Sergeant here maybe...","TWN":"不過中士再加上你，或許還有機會……"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"엄마도 같이 있잖아.","JPN":"お母さんも一緒じゃない。","ENG":"But Mom is here too.","TWN":"但偏偏我媽也在！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"나도 무모한 짓은 꽤나 해 본 편이지만, 저거한테서 휠체어를 끌고 도망칠 수 있을 것 같진 않아.","JPN":"私は無茶はいっぱいやってきた方だけど、あれから車椅子で逃げられるとは思えない。","ENG":"I’ve been able to get out of a lot of horrible situations, but I don’t think we’d be able to escape with Mom in a wheelchair.","TWN":"雖然我常常做事不經大腦，但想也知道推著一台輪椅是不可能逃得了的。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"각오를 다졌는가. 여인이여.","JPN":"覚悟はできたか。女よ。","ENG":"You finally seem resolved to meet your fate, woman.","TWN":"女人，準備好了嗎？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"고통은 짧으나 안식은 영원할지니. 역병의 고통에서 벗어나 평안 속에 잠들라.","JPN":"苦痛は一瞬だが安息は永遠。疫病の苦しみから逃れ、安らかに眠りたまえ。","ENG":"Worry not. The pain will be short, but you shall have eternal rest. Be freed of the plague and sleep in peace.","TWN":"痛苦是短暫的，安息是永遠的。脫離瘟疫的痛苦進入安息吧！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"너는…….","JPN":"貴様は……","ENG":"You...","TWN":"你……"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"반가워. 소문으로만 듣던 유명인을 실물로 다 만나 보네.","JPN":"どうも。噂で聞いた有名人物に実際会えるなんてね。","ENG":"Nice to meet you. I’ve heard so much about you, it’s great to finally meet you in person.","TWN":"你好～沒想到可以親眼見到傳說中的人物呢！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그래도 너무 소란을 피웠어. 모르스.","JPN":"それでも騒ぎすぎよ。モールス。","ENG":"Although, you seem to have caused a little bit of a commotion, Mors.","TWN":"但是莫爾斯，你鬧得太過火囉～"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};